"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[1286],{89408:e=>{e.exports=JSON.parse('{"functions":[{"name":"register","desc":"Joins (or creates) a shared toolbar identified by `options.mediumName`\\nand contributes the buttons in `options.buttons` to it. Returns a\\n[SharedToolbarHandle] for managing this peer\'s button state.\\n\\nCleans up automatically when `options.plugin` unloads.","params":[{"name":"options","desc":"","lua_type":"RegisterOptions"}],"returns":[{"desc":"","lua_type":"SharedToolbarHandle"}],"function_type":"static","source":{"line":138,"path":"modules/shared-toolbar/init.luau"}}],"properties":[],"types":[{"name":"ButtonSpec","desc":"Describes a button to register on the shared toolbar. `id` must be\\nunique within the calling peer.","lua_type":"{ id: string, title: string, tooltip: string?, iconId: string?, clickableWhenViewportHidden: boolean?, onClick: () -> () }","source":{"line":33,"path":"modules/shared-toolbar/init.luau"}},{"name":"RegisterOptions","desc":"Options passed to [SharedToolbar.register].\\n\\n- `plugin` \u2014 your plugin instance.\\n- `mediumName` \u2014 a name shared by every cooperating plugin; the\\n   `BindableEvent` parented under `StudioService` uses this as its name.\\n- `toolbarTitle` \u2014 the title to advertise. The peer with the lowest\\n   `peerId` wins, so authoritative naming is stable across reshuffles.\\n- `peerId` \u2014 a stable identifier for this plugin (e.g. its name).\\n- `protocolVersion` \u2014 optional override for the wire protocol version.\\n- `buttons` \u2014 list of buttons to contribute.","lua_type":"{ plugin: Plugin, mediumName: string, toolbarTitle: string, peerId: string, protocolVersion: number?, buttons: { ButtonSpec } }","source":{"line":57,"path":"modules/shared-toolbar/init.luau"}},{"name":"SharedToolbarHandle","desc":"Returned by [SharedToolbar.register]. The methods only affect this\\npeer\'s own buttons; calling them on another peer\'s `id` errors.","fields":[{"name":"setActive","lua_type":"(self, buttonId: string, isActive: boolean) -> ()","desc":""},{"name":"setEnabled","lua_type":"(self, buttonId: string, isEnabled: boolean) -> ()","desc":""},{"name":"destroy","lua_type":"(self) -> ()","desc":""}],"source":{"line":76,"path":"modules/shared-toolbar/init.luau"}}],"name":"SharedToolbar","desc":"Lets multiple Studio plugins cooperatively own a single\\n`PluginToolbar`. Peers discover each other through a shared\\n`BindableEvent` medium parented under `StudioService`, elect a leader\\n(lowest sessionId wins), and the leader builds the toolbar with every\\npeer\'s buttons mirrored onto it. Clicks, active state, and enabled\\nstate are forwarded to the originating peer over the same medium.\\n\\nWhy: installing several plugins that each call `plugin:CreateToolbar`\\nwith the same name produces duplicate toolbars in Studio. Sharing the\\ntoolbar via this module collapses them into one.","source":{"line":16,"path":"modules/shared-toolbar/init.luau"}}')}}]);